import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../services/authService';

const Navbar: React.FC = () => {
  const { user, logout } = useAuth();
  const location = useLocation();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [notifications, setNotifications] = useState({
    readyForSale: 0,
    lowWeight: 0,
    healthAlerts: 0
  });

  useEffect(() => {
    loadNotifications();
    const interval = setInterval(loadNotifications, 60000); // Cada minuto
    return () => clearInterval(interval);
  }, []);

  const loadNotifications = async () => {
    try {
      const [animalsRes, weightsRes] = await Promise.all([
        api.get('/animals'),
        api.get('/weights/ready-for-sale?peso_minimo=100').catch(() => ({ data: [] }))
      ]);

      const animals = animalsRes.data || [];
      const readyForSale = weightsRes.data || [];

      setNotifications({
        readyForSale: readyForSale.length,
        lowWeight: animals.filter((a: any) => a.categoria === 'lechon').length,
        healthAlerts: Math.floor(animals.length * 0.05) // 5% estimado
      });
    } catch (error) {
      console.error('Error cargando notificaciones:', error);
    }
  };

  const getTotalNotifications = () => {
    return notifications.readyForSale + notifications.lowWeight + notifications.healthAlerts;
  };

  const navStyle: React.CSSProperties = {
    background: 'linear-gradient(135deg, #2c3e50, #34495e)',
    padding: '0',
    boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
    position: 'sticky',
    top: 0,
    zIndex: 1000
  };

  const navContainerStyle: React.CSSProperties = {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '0 20px'
  };

  const logoStyle: React.CSSProperties = {
    color: 'white',
    fontSize: '28px',
    fontWeight: '700',
    textDecoration: 'none',
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
    padding: '15px 0'
  };

  const navLinksStyle: React.CSSProperties = {
    display: 'flex',
    listStyle: 'none',
    margin: 0,
    padding: 0,
    gap: '5px'
  };

  const mobileMenuStyle: React.CSSProperties = {
    position: 'absolute',
    top: '100%',
    left: 0,
    right: 0,
    background: 'linear-gradient(135deg, #2c3e50, #34495e)',
    boxShadow: '0 4px 20px rgba(0,0,0,0.2)',
    display: isMobileMenuOpen ? 'block' : 'none',
    zIndex: 1000
  };

  const hamburgerStyle: React.CSSProperties = {
    display: 'none',
    flexDirection: 'column',
    cursor: 'pointer',
    padding: '10px',
    gap: '4px'
  };

  const hamburgerLineStyle: React.CSSProperties = {
    width: '25px',
    height: '3px',
    backgroundColor: 'white',
    borderRadius: '2px',
    transition: 'all 0.3s ease'
  };

  const linkStyle: React.CSSProperties = {
    color: 'rgba(255,255,255,0.9)',
    textDecoration: 'none',
    padding: '15px 16px',
    borderRadius: '8px',
